class Solution:
    def minAbsoluteSumDiff(self, nums1, nums2):
        MOD = 10 ** 9 + 7
        n = len(nums1)
        base = sum(abs(nums1[i] - nums2[i]) for i in range(n))
        best = base
        for i in range(n):
            old = abs(nums1[i] - nums2[i])
            for v in nums1:
                cand = base - old + abs(v - nums2[i])
                if cand < best:
                    best = cand
        return best % MOD

