var minAbsoluteSumDiff = function(nums1, nums2) {
    const MOD = 1000000007;
    const n = nums1.length;
    let base = 0;
    for (let i = 0; i < n; i++) base += Math.abs(nums1[i] - nums2[i]);
    const srt = nums1.slice().sort((a, b) => a - b);
    const lowerBound = (arr, t) => {
        let lo = 0, hi = arr.length;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (arr[mid] < t) lo = mid + 1; else hi = mid;
        }
        return lo;
    };
    let bestGain = 0;
    for (let i = 0; i < n; i++) {
        const old = Math.abs(nums1[i] - nums2[i]);
        const t = nums2[i];
        const p = lowerBound(srt, t);
        if (p < n) bestGain = Math.max(bestGain, old - Math.abs(srt[p] - t));
        if (p > 0) bestGain = Math.max(bestGain, old - Math.abs(srt[p - 1] - t));
    }
    return ((base - bestGain) % MOD + MOD) % MOD;
};
